import{_ as i,C as s,o as t,c as r,a0 as o,b as l,w as a,a as c,E as d,a1 as h}from"./chunks/framework.DZNqfkJl.js";const k=JSON.parse('{"title":"Frontend Setup and Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"en/developer/frontend.md","filePath":"en/developer/frontend.md"}'),u={name:"en/developer/frontend.md"};function p(g,e,m,f,b,v){const n=s("Mermaid");return t(),r("div",null,[e[1]||(e[1]=o('<h1 id="frontend-setup-and-architecture" tabindex="-1">Frontend Setup and Architecture <a class="header-anchor" href="#frontend-setup-and-architecture" aria-label="Permalink to &quot;Frontend Setup and Architecture&quot;">​</a></h1><p>The <strong>Structo</strong> frontend is built using <strong>Nuxt 4</strong>, which runs on top of <strong>Vue 3</strong>. Nuxt provides a robust architecture by default, supporting Server-Side Rendering (SSR) or Static Site Generation (SSG) while naturally structuring the codebase.</p><h2 id="🚀-how-to-run-locally" tabindex="-1">🚀 How to Run Locally <a class="header-anchor" href="#🚀-how-to-run-locally" aria-label="Permalink to &quot;🚀 How to Run Locally&quot;">​</a></h2><h3 id="_1-install-dependencies" tabindex="-1">1. Install Dependencies <a class="header-anchor" href="#_1-install-dependencies" aria-label="Permalink to &quot;1. Install Dependencies&quot;">​</a></h3><p>Make sure you have Node.js (22 or higher) installed. Open your terminal, navigate to the frontend project, and install all dependencies:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h3 id="_2-environment-variables" tabindex="-1">2. Environment Variables <a class="header-anchor" href="#_2-environment-variables" aria-label="Permalink to &quot;2. Environment Variables&quot;">​</a></h3><p>Ensure you have configured the correct environments by reviewing or adjusting the respective file for local development. Nuxt 4 natively reads variables from <code>.env</code>.</p><h3 id="_3-start-the-development-server" tabindex="-1">3. Start the Development Server <a class="header-anchor" href="#_3-start-the-development-server" aria-label="Permalink to &quot;3. Start the Development Server&quot;">​</a></h3><p>To run the application with Hot Module Replacement (HMR):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>The web application will typically be served at <code>http://localhost:3000</code>.</p><hr><h2 id="🏗️-applied-patterns-and-ecosystem" tabindex="-1">🏗️ Applied Patterns and Ecosystem <a class="header-anchor" href="#🏗️-applied-patterns-and-ecosystem" aria-label="Permalink to &quot;🏗️ Applied Patterns and Ecosystem&quot;">​</a></h2><ul><li><strong>Strict Typescript</strong>: All core code, <code>stores</code>, and requests are strongly typed (TypeScript) to prevent runtime errors.</li><li><strong>Vuetify (UI Library)</strong>: <strong>Vuetify</strong> is heavily utilized as the main visual component framework (Material Design), providing a complete ecosystem of adaptive buttons, tables, grids, and directives.</li><li><strong>Pinia for State Management</strong>: Replaces Vuex. Used in the <code>stores/</code> folder to manage transparent and reactive global data flows throughout the application.</li><li><strong>Composables</strong>: Extensive use of the Vue 3 Composition API (<code>setup()</code>). Composables allow you to extract reusable logic and state into pages or components.</li><li><strong>Shared Auto-imports</strong>: Nuxt 4 auto-imports components, composables, and utilities by default, saving you from having to clutter the explicit imports section.</li></ul><h2 id="📁-directory-structure" tabindex="-1">📁 Directory Structure <a class="header-anchor" href="#📁-directory-structure" aria-label="Permalink to &quot;📁 Directory Structure&quot;">​</a></h2><p>The structure under the <code>frontend/app</code> folder follows Nuxt&#39;s conventional File-System Routing standard:</p>',17)),(t(),l(h,null,{default:a(()=>[d(n,{id:"mermaid-69",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20P%5Bpages%2F%5CnFile-based%20Routing%5D%20--%3E%20C%7Bcomponents%2F%5CnUI%20Components%7D%0A%20%20%20%20P%20--%3E%20COMP%5Bcomposables%2F%5CnReusable%20Vue%203%20Logic%5D%0A%20%20%20%20P%20--%3E%20S%5Bstores%2F%5CnPinia%20State%20Management%5D%0A%20%20%20%20%0A%20%20%20%20C%20--%3E%20COMP%0A%20%20%20%20C%20--%3E%20S%0A%20%20%20%20COMP%20-.%20API%20Request%20.-%3E%20API((Backend%20Ecosystem))%0A%20%20%20%20S%20-.%20Local%20Hydration%20.-%3E%20COMP%0A%20%20%20%20%0A%20%20%20%20style%20P%20fill%3A%2300DC82%2Cstroke%3A%23000%2Cstroke-width%3A2px%2Ccolor%3A%23000%0A%20%20%20%20style%20C%20fill%3A%2334495e%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20COMP%20fill%3A%2342b883%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20S%20fill%3A%23ffe12b%2Cstroke%3A%23a68e00%2Cstroke-width%3A2px%2Ccolor%3A%23000%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h3 id="app-main-directories-description" tabindex="-1">App Main Directories Description <a class="header-anchor" href="#app-main-directories-description" aria-label="Permalink to &quot;App Main Directories Description&quot;">​</a></h3><ul><li><strong>app.vue</strong>: The main component and visual entry point of the application.</li><li><strong>pages/</strong>: Hosts the <em>View</em> components. Each <code>.vue</code> file within this directory graphically represents a different web route.</li><li><strong>components/</strong>: Used for modular and reusable visual components. Nuxt will register them automatically around the project.</li><li><strong>layouts/</strong>: Allows setting common graphical shells (navbar, footer, sidebar, etc.) to be shared between different <code>pages</code>.</li><li><strong>composables/</strong>: Hosts exported functions (like <code>useMyLogic()</code>). Ideal for direct fetch requests, logical state, and form utilities.</li><li><strong>stores/</strong>: Defines the <strong>Pinia</strong> stores. Centralized data logic (e.g., the current user session, active cart, etc.).</li><li><strong>middleware/</strong>: Code that executes <em>before</em> transitioning to a particular route. (Ideal for authentication guards).</li><li><strong>plugins/</strong>: Global code that loads to initialize extra tools inside the Vue instance before rendering.</li><li><strong>public/</strong> and <strong>assets/</strong>: For static images, web fonts, or global stylesheets (like CSS/SCSS).</li></ul><hr><h2 id="🌐-http-fetch-flow" tabindex="-1">🌐 HTTP Fetch Flow <a class="header-anchor" href="#🌐-http-fetch-flow" aria-label="Permalink to &quot;🌐 HTTP Fetch Flow&quot;">​</a></h2><p>To communicate with the backend API, the application avoids native <code>fetch</code> or raw <code>axios</code> scattered throughout the code. Instead, it relies on Nuxt/Vue 3 composables (like a custom <code>$fetch</code> or <code>useFetch</code>).</p><ul><li><strong><code>apiFetch</code> / Custom Fetch:</strong> Typically, these wrappers automatically intercept requests to attach the <strong>JWT Token</strong> from the active session into the headers (<code>Authorization: Bearer &lt;token&gt;</code>).</li><li><strong>Usage:</strong> Call these fetch methods ideally inside your Pinia actions (stores) or directly within the <code>&lt;script setup&gt;</code> block of your components and composables.</li></ul><hr><h2 id="🔐-authentication-accounts-session" tabindex="-1">🔐 Authentication &amp; Accounts (Session) <a class="header-anchor" href="#🔐-authentication-accounts-session" aria-label="Permalink to &quot;🔐 Authentication &amp; Accounts (Session)&quot;">​</a></h2><p>The frontend integrates <strong><code>@sidebase/nuxt-auth</code></strong> to handle the entire session lifecycle securely.</p><ul><li><strong>Login and Logout:</strong> Use functions like <code>signIn()</code> and <code>signOut()</code> provided by the module. They negotiate token exchange with the backend and handle local storage.</li><li><strong>Protected Routes:</strong> Nuxt <code>middleware</code> (e.g., <code>definePageMeta({ middleware: &#39;auth&#39; })</code>) is applied inside individual <code>pages/</code> to block unauthenticated access, forcing redirects back to the login screen.</li><li><strong>User State:</strong> The connected user&#39;s payload (Claims, Roles) is globally accessible by using <code>useAuth()</code> or through a dedicated Pinia Session Store.</li></ul><hr><h2 id="🌍-internationalization-i18n" tabindex="-1">🌍 Internationalization (i18n) <a class="header-anchor" href="#🌍-internationalization-i18n" aria-label="Permalink to &quot;🌍 Internationalization (i18n)&quot;">​</a></h2><p>Multilingual support is achieved using the <strong><code>@nuxtjs/i18n</code></strong> Nuxt module.</p><ul><li><strong>Dictionaries:</strong> Translation mappings are defined either in configuration or through external files (e.g., <code>en.json</code>, <code>es.json</code>) usually kept in a <code>locales/</code> or similar directory.</li><li><strong>Usage inside Components:</strong> To output translated text, use the <code>$t(&#39;translation.key&#39;)</code> function in your Vue templates, or call the <code>useI18n()</code> composable within your scripts.</li><li><strong>Switching Locales:</strong> Exposes functions (like <code>setLocale(&#39;en&#39;)</code>) to actively toggle the platform&#39;s language on the fly.</li></ul><hr><h2 id="📝-environment-variables-and-configuration" tabindex="-1">📝 Environment Variables and Configuration <a class="header-anchor" href="#📝-environment-variables-and-configuration" aria-label="Permalink to &quot;📝 Environment Variables and Configuration&quot;">​</a></h2><p>The application spins up using variables defined in <code>.env</code> files located in the frontend root (such as <code>.env.local</code>, <code>.env.staging</code>, <code>.env.production</code>). Critical keys usually include:</p><ul><li><strong><code>NUXT_PUBLIC_API_BASE</code></strong> (or similar): Defines the absolute URL pointing to the backend (e.g., <code>http://localhost:5000/api</code>). Remember to review or scaffold your own <code>.env.local</code> file before running the project initially via <code>npm run dev</code>.</li></ul>',18))])}const A=i(u,[["render",p]]);export{k as __pageData,A as default};
